fn token(sum: i32, slot: usize, packed: bool, group: bool, reuse: bool) -> i32 {
    let mut v = sum + (slot as i32) * 7;
    if packed { v += 3; }
    if group { v += 5; }
    if reuse { v += 11; }
    v.rem_euclid(101)
}

