    let chosen = d3::dx(&(0..base_rows.len()).map(|i| i as i32).collect::<Vec<_>>(), &c.seq);
    let mut vals = Vec::new();
    let mut trace = Vec::new();
    for (pos, src) in c.seq.iter().enumerate() {
        let handle = moved[pos];
