	// If existing report.json exists, compare its rows against new raw rows
	if oldBuf, err := os.ReadFile(finalPath); err == nil {
		var oldDoc finalDoc
		if err := json.Unmarshal(oldBuf, &oldDoc); err == nil {
			// Build map of old report rows by case name
			oldMap := make(map[string]entry)
